body.script:
let scanCount = 0;
let rejectCount = 0;
let isProcessing = false;

function playBeep(success) {
    try {
        const ctx = new AudioContext();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.frequency.value = success ? 880 : 220;
        osc.type = success ? 'sine' : 'square';
        gain.gain.value = 0.3;
        osc.start();
        osc.stop(ctx.currentTime + (success ? 0.15 : 0.4));
    } catch(e) { /* Audio not available */ }
}

function showResult(data) {
    const panel = document.getElementById('result-panel');
    let cls = data.success ? 'result-success' : 'result-error';
    let icon = data.success ? '✅' : '❌';

    if (!data.success && data.message && data.message.indexOf('DÉJÀ') !== -1) {
        cls = 'result-warning';
        icon = '⚠️';
    }

    let detailsHtml = '';
    if (data.ticket_data) {
        const td = data.ticket_data;
        if (td.name) detailsHtml += '<div>N° Billet: <span>' + td.name + '</span></div>';
        if (td.holder) detailsHtml += '<div>Porteur: <span>' + td.holder + '</span></div>';
        if (td.match) detailsHtml += '<div>Match: <span>' + td.match + '</span></div>';
        if (td.zone) detailsHtml += '<div>Zone: <span>' + td.zone + '</span></div>';
        if (td.stadium) detailsHtml += '<div>Stade: <span>' + td.stadium + '</span></div>';
        if (td.scan_time) detailsHtml += '<div>Heure scan: <span>' + td.scan_time + '</span></div>';
        if (td.current_headcount !== undefined) {
            detailsHtml += '<div>Affluence zone: <span>' + td.current_headcount + ' spectateurs</span></div>';
        }
    }

    panel.innerHTML =
        '<div class="result-card ' + cls + '">' +
        '<div class="icon">' + icon + '</div>' +
        '<div class="msg">' + data.message + '</div>' +
        '<div class="details">' + detailsHtml + '</div>' +
        '</div>';

    setTimeout(function() { panel.innerHTML = ''; }, 5000);
}

function validateBarcode(barcode) {
    if (isProcessing) return;
    isProcessing = true;

    fetch('/ticket/scan/validate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            jsonrpc: '2.0',
            method: 'call',
            params: { barcode: barcode }
        })
    })
    .then(function(response) { return response.json(); })
    .then(function(json) {
        var result = json.result || json;
        playBeep(result.success);
        showResult(result);
        if (result.success) {
            scanCount++;
            document.getElementById('scan-count').textContent = scanCount;
        } else {
            rejectCount++;
            document.getElementById('reject-count').textContent = rejectCount;
        }
    })
    .catch(function(err) {
        playBeep(false);
        showResult({ success: false, message: '❌ Erreur réseau: ' + err.message });
        rejectCount++;
        document.getElementById('reject-count').textContent = rejectCount;
    })
    .finally(function() { isProcessing = false; });
}

function manualScan() {
    var input = document.getElementById('barcode-input');
    if (input.value.trim()) {
        validateBarcode(input.value.trim());
        input.value = '';
    }
}

document.getElementById('barcode-input').addEventListener('keyup', function(e) {
    if (e.key === 'Enter') manualScan();
});

var html5QrCode = new Html5Qrcode('reader');
html5QrCode.start(
    { facingMode: 'environment' },
    { fps: 10, qrbox: { width: 250, height: 250 } },
    function(decodedText) { validateBarcode(decodedText); },
    function(errorMessage) { /* Scan continu */ }
).catch(function(err) {
    console.warn('Caméra non disponible.', err);
    document.getElementById('reader-container').innerHTML =
        '<p style="text-align:center;color:#e94560;padding:20px;">📷 Caméra non disponible.<br/>Utilisez la saisie manuelle ci-dessous.</p>';
});
